import React, { Component } from "react";
import { connect } from "react-redux";
import { Icon, Avatar } from "antd";

class LandingThree extends Component {
  render() {
    return (
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          flexDirection: "row",
          height: "80vh",
          backgroundColor: "#1890ff"
        }}
      >
        <div>Say Hello!</div>
      </div>
    );
  }
}

const mapStateToProps = state => {
  const { batmode } = state.theme;
  return { batmode };
};

export default connect(mapStateToProps)(LandingThree);
